+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; size: number}
+	| {type: 'fr'; fraction: number; minimum: number}
+	| {type: 'auto'};
+
+type Placement = {start: number; end: number};
+
+const gridChildren = (node: DOMElement) =>
+	node.childNodes.filter((child): child is DOMElement => Boolean(child.yogaNode));
+
+const parseTracks = (value: string | undefined): Track[] => {
+	if (!value) return [];
+
+	const tokens = value.match(/minmax\\([^)]*\\)|\\S+/g) ?? [];
+	return tokens.map(token => {
+		const minmax = /^minmax\\(\\s*(\\d+(?:\\.\\d+)?)\\s*,\\s*(\\d+(?:\\.\\d+)?fr|\\d+(?:\\.\\d+)?)\\s*\\)$/.exec(token);
+		if (minmax) {
+			const minimum = Number(minmax[1]);
+			const maximum = minmax[2];
+			if (maximum.endsWith('fr')) {
+				return {type: 'fr', fraction: Number(maximum.slice(0, -2)), minimum};
+			}
+
+			return {type: 'fixed', size: Number(maximum)};
+		}
+
+		if (token === 'auto') return {type: 'auto'};
+		if (token.endsWith('fr')) {
+			return {type: 'fr', fraction: Number(token.slice(0, -2)), minimum: 0};
+		}
+
+		return {type: 'fixed', size: Number(token)};
+	});
+};
+
+const gapFor = (node: DOMElement, axis: 'row' | 'column') =>
+	axis === 'row'
+		? node.style.rowGap ?? node.style.gap ?? 0
+		: node.style.columnGap ?? node.style.gap ?? 0;
+
+const sizeTracks = (tracks: Track[], available: number, gap: number, autoSizes: number[]) => {
+	const gaps = Math.max(0, tracks.length - 1) * gap;
+	let used = gaps;
+	let fractions = 0;
+	const sizes = tracks.map((track, index) => {
+		if (track.type === 'fixed') {
+			used += track.size;
+			return track.size;
+		}
+
+		if (track.type === 'auto') {
+			const size = autoSizes[index] ?? 0;
+			used += size;
+			return size;
+		}
+
+		used += track.minimum;
+		fractions += track.fraction;
+		return track.minimum;
+	});
+
+	const remaining = Math.max(0, available - used);
+	if (fractions > 0) {
+		tracks.forEach((track, index) => {
+			if (track.type === 'fr') sizes[index] += (remaining * track.fraction) / fractions;
+		});
+	}
+
+	return sizes;
+};
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number' && Number.isInteger(value) && value > 0) {
+		return {start: value - 1, end: value};
+	}
+
+	if (typeof value !== 'string') return undefined;
+	const match = /^(\\d+)\\s*\\/\\s*(\\d+)$/.exec(value);
+	if (!match) return undefined;
+	const start = Number(match[1]) - 1;
+	const end = Number(match[2]) - 1;
+	return start >= 0 && end > start ? {start, end} : undefined;
+};
+
+const placementsFor = (children: DOMElement[], columns: number): Array<{column: Placement; row: Placement}> => {
+	const occupied = new Set<string>();
+	const result: Array<{column: Placement; row: Placement}> = [];
+	let cursor = 0;
+
+	for (const child of children) {
+		const specifiedColumn = parsePlacement(child.style.gridColumn);
+		const specifiedRow = parsePlacement(child.style.gridRow);
+		let column = specifiedColumn;
+		let row = specifiedRow;
+
+		if (!column || !row) {
+			while (true) {
+				const candidateRow = Math.floor(cursor / columns);
+				const candidateColumn = cursor % columns;
+				cursor++;
+				if (!occupied.has(`${candidateRow}:${candidateColumn}`)) {
+					column ??= {start: candidateColumn, end: candidateColumn + 1};
+					row ??= {start: candidateRow, end: candidateRow + 1};
+					break;
+				}
+			}
+		}
+
+		for (let y = row.start; y < row.end; y++) {
+			for (let x = column.start; x < column.end; x++) occupied.add(`${y}:${x}`);
+		}
+		result.push({column, row});
+	}
+
+	return result;
+};
+
+const offsetsFor = (sizes: number[], gap: number) => {
+	let offset = 0;
+	return sizes.map(size => {
+		const current = offset;
+		offset += size + gap;
+		return current;
+	});
+};
+
+const spanSize = (sizes: number[], placement: Placement, gap: number) =>
+	sizes.slice(placement.start, placement.end).reduce((sum, size) => sum + size, 0) +
+	Math.max(0, placement.end - placement.start - 1) * gap;
+
+const visit = (node: DOMElement, callback: (element: DOMElement) => void): void => {
+	callback(node);
+	for (const child of gridChildren(node)) visit(child, callback);
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	if (node.style.display !== 'grid' || !node.yogaNode) return;
+	const children = gridChildren(node);
+	if (children.length === 0) return;
+
+	const columnTracks = parseTracks(node.style.gridTemplateColumns);
+	const columns = columnTracks.length || 1;
+	const placements = placementsFor(children, columns);
+	const paddingX = node.yogaNode.getComputedPadding(Yoga.EDGE_LEFT) + node.yogaNode.getComputedPadding(Yoga.EDGE_RIGHT) + node.yogaNode.getComputedBorder(Yoga.EDGE_LEFT) + node.yogaNode.getComputedBorder(Yoga.EDGE_RIGHT);
+	const paddingY = node.yogaNode.getComputedPadding(Yoga.EDGE_TOP) + node.yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) + node.yogaNode.getComputedBorder(Yoga.EDGE_TOP) + node.yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const contentWidth = Math.max(0, node.yogaNode.getComputedWidth() - paddingX);
+	const columnGap = gapFor(node, 'column');
+	const autoColumns = columnTracks.map((track, index) => track.type === 'auto' ? Math.max(0, ...children.filter((_, childIndex) => placements[childIndex].column.start === index && placements[childIndex].column.end === index + 1).map(child => child.yogaNode!.getComputedWidth())) : 0);
+	const columnSizes = sizeTracks(columnTracks.length ? columnTracks : [{type: 'auto'}], contentWidth, columnGap, autoColumns);
+	const columnOffsets = offsetsFor(columnSizes, columnGap);
+
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index];
+		child.yogaNode!.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.yogaNode!.setPosition(Yoga.EDGE_LEFT, columnOffsets[placement.column.start]);
+		child.yogaNode!.setPosition(Yoga.EDGE_TOP, 0);
+		child.yogaNode!.setWidth(spanSize(columnSizes, placement.column, columnGap));
+	}
+
+	const rowCount = Math.max(1, ...placements.map(placement => placement.row.end));
+	const parsedRows = parseTracks(node.style.gridTemplateRows);
+	const rowTracks = Array.from({length: Math.max(rowCount, parsedRows.length)}, (_, index) => parsedRows[index] ?? {type: 'auto'} as Track);
+	const rowGap = gapFor(node, 'row');
+	const autoRows = rowTracks.map((track, row) => track.type === 'auto' ? Math.max(0, ...children.filter((_, index) => placements[index].row.start === row && placements[index].row.end === row + 1).map(child => child.yogaNode!.getComputedHeight())) : 0);
+	const explicitHeight = typeof node.style.height === 'number';
+	const availableHeight = explicitHeight ? Math.max(0, node.style.height - paddingY) : rowTracks.reduce((sum, track, index) => sum + (track.type === 'auto' ? autoRows[index] : track.type === 'fixed' ? track.size : track.minimum), 0) + Math.max(0, rowTracks.length - 1) * rowGap;
+	const rowSizes = sizeTracks(rowTracks, availableHeight, rowGap, autoRows);
+	const rowOffsets = offsetsFor(rowSizes, rowGap);
+
+	if (!explicitHeight) node.yogaNode.setHeight(rowSizes.reduce((sum, size) => sum + size, 0) + Math.max(0, rowSizes.length - 1) * rowGap + paddingY);
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index];
+		child.yogaNode!.setPosition(Yoga.EDGE_TOP, rowOffsets[placement.row.start]);
+		child.yogaNode!.setHeight(spanSize(rowSizes, placement.row, rowGap));
+	}
+};
+
+export const calculateLayoutWithGrid = (root: DOMElement, width: number, height?: number): void => {
+	root.yogaNode!.setWidth(width);
+	root.yogaNode!.calculateLayout(width, height, Yoga.DIRECTION_LTR);
+
+	// The first calculation supplies container dimensions and intrinsic item sizes.
+	visit(root, layoutGrid);
+	root.yogaNode!.calculateLayout(width, height, Yoga.DIRECTION_LTR);
+	// Item widths now constrain text measurement, so calculate automatic row heights.
+	visit(root, layoutGrid);
+	root.yogaNode!.calculateLayout(width, height, Yoga.DIRECTION_LTR);
+};
